import React from "react"
import { useStaticQuery, graphql } from "gatsby"
import Image from "gatsby-image"

const Projects = () => {
  const data = useStaticQuery(graphql`
    {
      allContentfulProjects {
        nodes {
          id
          code
          demo
          title
          description {
            description
          }
          technologies {
            technologies
          }
          image {
            fluid {
              ...GatsbyContentfulFluid
            }
          }
        }
      }
    }
  `)
  const {
    allContentfulProjects: { nodes: projects },
  } = data

  return (
    <section id="projects">
      {projects.map(project => {
        return (
          <div key={project.id}>
            <h3>{project.title}</h3>
            <p className="p7">{project.technologies.technologies}</p>
            <div className="project">
              <div className="overlay"></div>
              <Image
                style={{
                  position: "absolute",
                  left: 0,
                  top: 0,
                  width: "100%",
                  height: "100%",
                  borderRadius: "10px",
                }}
                fluid={project.image.fluid}
              />

              <a
                href={project.demo}
                target="_blank"
                className="btn btn-project"
                rel="noopener noreferrer"
              >
                Demo
              </a>
              <a
                href={project.code}
                target="_blank"
                className="btn btn-project"
                rel="noopener noreferrer"
              >
                Code
              </a>
              <p className="p7">{project.description.description}</p>
            </div>
          </div>
        )
      })}
    </section>
  )
}

export default Projects
